-- Gear For Life STAGING CORRECTIONS - DRAFT
-- Purpose: replace confirmed product-specific decoration staging rows for 13 GFL SKUs.
-- Scope: supplier_decoration_options and supplier_decoration_price_rows only.
-- Not included: products, url_pages, navigation, transforms, or storefront publishing.
-- Run manually in Supabase only after reviewing this file.
-- Safety: guards stop if the raw load is incomplete, already corrected, or not in the expected state.

begin;

do $$
declare
  gfl_batch_id uuid;
  affected_skus text[] := array['IGOISB', 'IGSCFAK', 'PODCB', 'POEB', 'POEGB', 'POGB', 'POOMTT', 'POOPB', 'POPIB', 'PORC', 'POSWTS', 'POVCB', 'POWBC']::text[];
begin
  select id into gfl_batch_id
  from public.supplier_import_batches
  where supplier = 'Gear For Life'
    and source_file_hash = 'f20ede9ac24d944fcb4c3c646d8ae2cbc41d2c63580200db27f2e86a96bf739c'
  order by created_at desc
  limit 1;

  if gfl_batch_id is null then
    raise exception 'Gear For Life batch not found. Stop: run the raw load first.';
  end if;

  if (select count(*) from public.supplier_raw_product_rows where batch_id = gfl_batch_id) <> 472 then
    raise exception 'Expected 472 GFL raw product rows before correction.';
  end if;

  if (select count(*) from public.supplier_raw_colour_options where batch_id = gfl_batch_id) <> 892 then
    raise exception 'Expected 892 GFL raw colour rows before correction.';
  end if;

  if (select count(*) from public.supplier_raw_images where batch_id = gfl_batch_id) <> 2416 then
    raise exception 'Expected 2416 GFL raw image rows before correction.';
  end if;

  if (select count(*) from public.supplier_price_rows where batch_id = gfl_batch_id) <> 773 then
    raise exception 'Expected 773 GFL product price rows before correction.';
  end if;

  if (select count(*) from public.supplier_decoration_options where batch_id = gfl_batch_id) <> 273 then
    raise exception 'Expected 273 GFL decoration options before correction. Stop: maybe already corrected.';
  end if;

  if (select count(*) from public.supplier_decoration_price_rows where batch_id = gfl_batch_id) <> 1069 then
    raise exception 'Expected 1069 GFL decoration price rows before correction. Stop: maybe already corrected.';
  end if;

  if (select count(*) from public.supplier_decoration_rate_cards where batch_id = gfl_batch_id) <> 2 then
    raise exception 'Expected 2 GFL decoration rate cards before correction.';
  end if;

  if (select count(*) from public.supplier_decoration_rate_card_rows where batch_id = gfl_batch_id) <> 160 then
    raise exception 'Expected 160 GFL decoration rate card rows before correction.';
  end if;

  if (
    select count(*)
    from public.supplier_decoration_options
    where batch_id = gfl_batch_id
      and supplier = 'Gear For Life'
      and supplier_sku = any(affected_skus)
  ) <> 45 then
    raise exception 'Expected 45 old affected decoration options. Stop: review current staging state.';
  end if;

  if (
    select count(*)
    from public.supplier_decoration_price_rows
    where batch_id = gfl_batch_id
      and supplier = 'Gear For Life'
      and supplier_sku = any(affected_skus)
  ) <> 165 then
    raise exception 'Expected 165 old affected decoration price rows. Stop: review current staging state.';
  end if;

  if exists (
    select 1
    from public.supplier_decoration_price_rows
    where batch_id = gfl_batch_id
      and supplier = 'Gear For Life'
      and price_status = 'request_quote'
      and unit_cost is not null
  ) then
    raise exception 'Existing request_quote decoration price rows must have unit_cost null before correction.';
  end if;
end $$;

with gfl_batch as (
  select id as batch_id
  from public.supplier_import_batches
  where supplier = 'Gear For Life'
    and source_file_hash = 'f20ede9ac24d944fcb4c3c646d8ae2cbc41d2c63580200db27f2e86a96bf739c'
  order by created_at desc
  limit 1
),
affected_skus as (
  select unnest(array['IGOISB', 'IGSCFAK', 'PODCB', 'POEB', 'POEGB', 'POGB', 'POOMTT', 'POOPB', 'POPIB', 'PORC', 'POSWTS', 'POVCB', 'POWBC']::text[]) as supplier_sku
)
delete from public.supplier_decoration_price_rows p
using gfl_batch, affected_skus a
where p.batch_id = gfl_batch.batch_id
  and p.supplier = 'Gear For Life'
  and p.supplier_sku = a.supplier_sku;

with gfl_batch as (
  select id as batch_id
  from public.supplier_import_batches
  where supplier = 'Gear For Life'
    and source_file_hash = 'f20ede9ac24d944fcb4c3c646d8ae2cbc41d2c63580200db27f2e86a96bf739c'
  order by created_at desc
  limit 1
),
affected_skus as (
  select unnest(array['IGOISB', 'IGSCFAK', 'PODCB', 'POEB', 'POEGB', 'POGB', 'POOMTT', 'POOPB', 'POPIB', 'PORC', 'POSWTS', 'POVCB', 'POWBC']::text[]) as supplier_sku
)
delete from public.supplier_decoration_options d
using gfl_batch, affected_skus a
where d.batch_id = gfl_batch.batch_id
  and d.supplier = 'Gear For Life'
  and d.supplier_sku = a.supplier_sku;

