    ('Gear For Life', 'POOMTT', 'poomtt|laser_engraving|slat_leg', 'Laser Engraving', 'Slat / Leg', 'Slat / Leg', null, 'AUD', 250, null, null, 75.00, null, 'per_position', 'request_quote', '{"supplier_sku":"POOMTT","product_name":"Ombrello Tavolo Table","decoration_method":"Laser Engraving","decoration_area":"Slat / Leg","artwork_size_label":"","tier_1_plus":"","tier_10_plus":"","tier_25_49_or_25_plus":"POA","tier_50_99_or_50_plus":"POA","tier_100_249_or_100_plus":"POA","tier_250_plus":"POA","tier_500_plus":"POA","setup_cost":"75.00","setup_frequency":"per_order","price_status_note":"request_quote_all_tiers","packing_fee_note":"","cost_scope":"branding_only","gst_note":"ex_gst","source_note":"Laser Engraving location is POA with no fixed pricing.","source":"manual_review_product_specific_branding_correction","source_file":"gear_for_life_product_specific_branding_corrections_DRAFT.csv","source_row_number":50,"tier_column":"tier_250_plus","raw_price":"POA","supplier_specific":true}'::jsonb),
    ('Gear For Life', 'POOMTT', 'poomtt|laser_engraving|slat_leg', 'Laser Engraving', 'Slat / Leg', 'Slat / Leg', null, 'AUD', 500, null, null, 75.00, null, 'per_position', 'request_quote', '{"supplier_sku":"POOMTT","product_name":"Ombrello Tavolo Table","decoration_method":"Laser Engraving","decoration_area":"Slat / Leg","artwork_size_label":"","tier_1_plus":"","tier_10_plus":"","tier_25_49_or_25_plus":"POA","tier_50_99_or_50_plus":"POA","tier_100_249_or_100_plus":"POA","tier_250_plus":"POA","tier_500_plus":"POA","setup_cost":"75.00","setup_frequency":"per_order","price_status_note":"request_quote_all_tiers","packing_fee_note":"","cost_scope":"branding_only","gst_note":"ex_gst","source_note":"Laser Engraving location is POA with no fixed pricing.","source":"manual_review_product_specific_branding_correction","source_file":"gear_for_life_product_specific_branding_corrections_DRAFT.csv","source_row_number":50,"tier_column":"tier_500_plus","raw_price":"POA","supplier_specific":true}'::jsonb)
) as v(supplier, supplier_sku, decoration_option_key, decoration_method, decoration_area, decoration_location, artwork_size_label, currency, min_qty, max_qty, unit_cost, setup_cost, repeat_setup_cost, pricing_basis, price_status, raw_json)
join public.supplier_decoration_options d
  on d.batch_id = gfl_batch.batch_id
 and d.supplier = v.supplier::text
 and d.supplier_sku = v.supplier_sku::text
 and d.decoration_option_key = v.decoration_option_key::text;

do $$
declare
  gfl_batch_id uuid;
  affected_skus text[] := array['IGOISB', 'IGSCFAK', 'PODCB', 'POEB', 'POEGB', 'POGB', 'POOMTT', 'POOPB', 'POPIB', 'PORC', 'POSWTS', 'POVCB', 'POWBC']::text[];
begin
  select id into gfl_batch_id
  from public.supplier_import_batches
  where supplier = 'Gear For Life'
    and source_file_hash = 'f20ede9ac24d944fcb4c3c646d8ae2cbc41d2c63580200db27f2e86a96bf739c'
  order by created_at desc
  limit 1;

  if (select count(*) from public.supplier_decoration_options where batch_id = gfl_batch_id) <> 277 then
    raise exception 'Post-correction decoration option total mismatch.';
  end if;

  if (select count(*) from public.supplier_decoration_price_rows where batch_id = gfl_batch_id) <> 1118 then
    raise exception 'Post-correction decoration price row total mismatch.';
  end if;

  if (
    select count(*)
    from public.supplier_decoration_options
    where batch_id = gfl_batch_id
      and supplier = 'Gear For Life'
      and supplier_sku = any(affected_skus)
  ) <> 49 then
    raise exception 'Post-correction affected decoration option count mismatch.';
  end if;

  if (
    select count(*)
    from public.supplier_decoration_price_rows
    where batch_id = gfl_batch_id
      and supplier = 'Gear For Life'
      and supplier_sku = any(affected_skus)
  ) <> 214 then
    raise exception 'Post-correction affected decoration price row count mismatch.';
  end if;

  if exists (
    select 1
    from public.supplier_decoration_price_rows
    where batch_id = gfl_batch_id
      and supplier = 'Gear For Life'
      and supplier_sku = any(affected_skus)
      and price_status = 'request_quote'
      and unit_cost is not null
  ) then
    raise exception 'POA/request_quote correction rows must have unit_cost null.';
  end if;

  if exists (
    select 1
    from public.supplier_decoration_price_rows
    where batch_id = gfl_batch_id
      and supplier = 'Gear For Life'
      and supplier_sku = any(affected_skus)
      and price_status = 'priced'
      and unit_cost is null
  ) then
    raise exception 'Priced correction rows must have a unit_cost.';
  end if;

  if exists (
    select 1
    from public.supplier_decoration_price_rows
    where batch_id = gfl_batch_id
      and supplier = 'Gear For Life'
      and supplier_sku = any(affected_skus)
      and supplier_decoration_option_id is null
  ) then
    raise exception 'Correction price rows must be linked to supplier_decoration_options.';
  end if;
end $$;

commit;

